      assert coalSum == CoalitionSeatSum(a, coalition);  // Trigger CoalitionSeatSumAppend lemma
    }
    j := j + 1;
  }
  assert a[..n] == a;

  // Step 3: Check if coalition has strict majority
  if coalSum * 2 > totalSum {
    k := |coalition|;
    assert coalition[0] == 1;
  } else {
    k := 0;
    coalition := [];
  }
}

