ghost function CoalitionSeatSum(a: seq<int>, coalition: seq<int>): int
  decreases |coalition|
{
  if |coalition| == 0 then 0
  else if 1 <= coalition[|coalition|-1] <= |a|
    then CoalitionSeatSum(a, coalition[..|coalition|-1]) + a[coalition[|coalition|-1] - 1]
