// majority, no valid coalition exists.
ghost function EligibleSum(a: seq<int>): int
  requires |a| >= 1
  decreases |a|
{
  if |a| == 1 then a[0]
  else if a[|a| - 1] * 2 <= a[0] then EligibleSum(a[..|a| - 1]) + a[|a| - 1]
  else EligibleSum(a[..|a| - 1])
}

